// ============================================================
// Golden-master fixtures — the levels the harness replays.
// ============================================================
// These are fixed level strings + a fixed "jump script" (which
// step numbers to tap on). The golden harness runs each one with
// the real physics and records a trace, so we can prove a refactor
// changed NOTHING. Keep these frozen — if you change a level here,
// you must regenerate the golden traces on purpose.
//
// The first eight are copies of the game's built-in levels (from
// server.js SEED). The rest are little "showcase" levels that make
// sure the newer gadgets — the catapult (U), the gravity flip (u/n)
// landing on a ceiling, and flying (f/c) — get exercised too.
//
// A down-ramp is written  \\  in these template strings so a single
// backslash survives (same rule as server.js and stored levels).
//
// Some levels also have a `holdAt` script: pairs of [fromStep, toStep]
// where a finger is held DOWN. Tapping is what a cube needs; holding
// is what a rocket needs, so the flying levels use this instead of
// (or as well as) jumpAt.

"use strict";

// Tap the jump button every `n` steps, `count` times: [0, n, 2n, ...].
// Used by the built-in levels so the cube hops along instead of just
// running into the first spike. The pattern is fixed, so the trace is too.
function every(n, count) {
  const out = [];
  for (let i = 0; i < count; i++) out.push(i * n);
  return out;
}

